import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { Button, Input, Select, dispatchAppToast } from '@linm-soft-org/linm-web-common-components';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import { useVoucherInitData } from '../../../hooks/useVoucherInitData';
import { useDieuChinhKhoPermissions } from '../../../hooks/useDieuChinhKhoPermissions';
import { useAppDispatch } from '../../../store/hooks';
import { wmsService } from '../../../services/kho/wmsService';
import { KHO_PATHS } from '../../../appPaths';
import { dieuChinhKhoPageLabels } from '../../../constants/dieuChinhKhoPageLabels';
import { DocumentFormHeader } from '../../../components/layout';
import { VoucherDocumentFormShell } from '../../../components/form';
import df from '../../../styles/documentForm.module.css';

const DieuChinhKhoPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const navigate = useNavigate();
  const { canWrite } = useDieuChinhKhoPermissions();
  const [warehouseId, setWarehouseId] = useState('');
  const [materialCode, setMaterialCode] = useState('');
  const [unitCode, setUnitCode] = useState('');
  const [quantity, setQuantity] = useState(0);
  const [unitPrice, setUnitPrice] = useState(0);
  const [reason, setReason] = useState('');
  const [saving, setSaving] = useState(false);

  const { warehouseOptions } = useVoucherInitData('create-stock-adjustment');
  const whOpts = [{ value: '', label: '— Kho —' }, ...warehouseOptions];

  const handleSave = async () => {
    if (!warehouseId || !materialCode.trim()) {
      dispatchAppToast(dispatch, { message: dieuChinhKhoPageLabels.headerWarning, type: 'warning' });
      return;
    }
    setSaving(true);
    try {
      await wmsService.createStockAdjustment({
        warehouseId,
        materialCode: materialCode.trim(),
        unitCode,
        quantity,
        unitPrice,
        reason: reason || undefined,
      });
      dispatchAppToast(dispatch, { message: dieuChinhKhoPageLabels.saveSuccess, type: 'success' });
      setMaterialCode('');
      setQuantity(0);
      setUnitPrice(0);
      setReason('');
    } catch (err: unknown) {
      dispatchAppToast(dispatch, {
        message: getApiErrorMessage(err, dieuChinhKhoPageLabels.saveError),
        type: 'error',
      });
    } finally {
      setSaving(false);
    }
  };

  return (
    <VoucherDocumentFormShell
      testId="erp-kho-dieu-chinh-kho-form"
      header={(
        <DocumentFormHeader
          onBack={() => navigate(KHO_PATHS.tonKho)}
          title="Điều chỉnh kho"
          isNew
          isReadOnly={!canWrite}
          saving={saving}
          saveLabel="Lưu điều chỉnh"
          onSave={canWrite ? handleSave : undefined}
          extraActions={
            <Button variant="secondary" onClick={() => navigate(KHO_PATHS.tonKho)}>Xem tồn kho</Button>
          }
        />
      )}
    >
      <div className={df.section}>
        <h2 className={df.sectionTitle}>Thông tin điều chỉnh</h2>
        <div className={df.row4}>
          <div className={df.field}>
            <label className={df.label}>Kho</label>
            <Select value={warehouseId} onChange={e => setWarehouseId(e.target.value)} options={whOpts} disabled={!canWrite} />
          </div>
          <div className={df.field}>
            <label className={df.label}>Mã vật tư</label>
            <Input value={materialCode} onChange={e => setMaterialCode(e.target.value)} disabled={!canWrite} />
          </div>
          <div className={df.field}>
            <label className={df.label}>ĐVT</label>
            <Input value={unitCode} onChange={e => setUnitCode(e.target.value)} disabled={!canWrite} />
          </div>
          <div className={df.field}>
            <label className={df.label}>Số lượng điều chỉnh</label>
            <Input type="number" value={String(quantity)} onChange={e => setQuantity(Number(e.target.value))} disabled={!canWrite} />
          </div>
        </div>
        <div className={df.row4}>
          <div className={df.field}>
            <label className={df.label}>Đơn giá</label>
            <Input type="number" value={String(unitPrice)} onChange={e => setUnitPrice(Number(e.target.value))} disabled={!canWrite} />
          </div>
          <div className={`${df.field} ${df.spanCol3}`}>
            <label className={df.label}>Lý do</label>
            <textarea className={df.textarea} value={reason} onChange={e => setReason(e.target.value)} rows={1} disabled={!canWrite} />
          </div>
        </div>
      </div>
    </VoucherDocumentFormShell>
  );
};

export default DieuChinhKhoPage;
